# Skeptic review S51-T1-A-E2: verify PASS/CONTINUE only on taught contract
def assess(record: dict) -> str:
    required = {'trace_id', 'versions', 'spans', 'case_id', 'pii_in_trace'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if not (not record["trace_id"] or record["pii_in_trace"]) else "REDACT_AND_QUARANTINE_TRACE"

valid = {'case_id': 'CASO-MOQ-051-1A', 'trace_id': 'tr-moq-51', 'spans': {'retrieval', 'tool', 'answer', 'prompt'}, 'versions': {'prompt': 'p3', 'model': 'm2', 'index': 'i4'}, 'pii_in_trace': False}
invalid = {'case_id': 'CASO-MOQ-051-1A', 'trace_id': 'tr-moq-51', 'spans': {'retrieval', 'prompt', 'answer', 'tool'}, 'versions': {'prompt': 'p3', 'model': 'm2', 'index': 'i4'}, 'pii_in_trace': True}
incomplete = {**valid}
incomplete.pop('pii_in_trace', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

